The index definition that you create in this tutorial indexes the
following fields in the `sample_airbnb.listingsAndReviews`
collection:

- `summary` field as the `autoEmbed` type to automatically
  generate embeddings for the text data in the field using the
  `voyage-4` embedding model.

- `address.country` field as the `filter` type to prefilter the
  data for the semantic search using the string value in the field.

- `bedroom` field as the `filter` type to prefilter the data for
  the semantic search using the numeric value in the field.

To create this index:

To learn more, see [Compass](atlas-connect-via-compass).

On the Database screen, expand the name of the
database, `sample_airbnb`, then click the name of the collection,
`listingsAndReviews`.

- Click the Indexes tab, then select Search Indexes.

- Click Create Atlas Search Index to open the index creation dialog box.

- Enter `vector_index` as the name of the index.

- Define the MongoDB Vector Search index.

  ```json
  {
    "fields": [
      {
        "type": "autoEmbed",
        "modality": "text",
        "path": "summary",
        "model": "voyage-4"
      },
      {
        "type": "filter",
        "path": "address.country"
      },
      {
        "type": "filter",
        "path": "bedrooms"
      }
    ]
  }
  ```

- Click Create Search Index.

To learn more, see [MongoDB Shell](connect-mongo-shell).

> **Example:** **Input:**
>
> ```shell
> use sample_airbnb
> ```
>
> **Output:**
>
> ```shell
> switched to db sample_airbnb
> ```

To create the index named `vector_index`, run the following
`db.collection.createSearchIndex()` method:

```javascript
db.listingsAndReviews.createSearchIndex(
  "vector_index",
  "vectorSearch", 
  {
    "fields": [
      {
        "type": "autoEmbed",
        "modality": "text",
        "path": "summary",
        "model": "voyage-4"
      },
      {
        "type": "filter",
        "path": "address.country"
      },
      {
        "type": "filter",
        "path": "bedrooms"
      }
    ]
  }
);
```

To define a MongoDB Vector Search auto-embedding index, complete the following steps:

- Run the following command in your terminal to create a `.go` file in
  a Go project directory:

  ```shell
  touch create-index.go
  ```

- Copy and paste the following index definition into the file:

  ```go
  package main

  import (
  	"context"
  	"fmt"
  	"log"
  	"time"

  	"go.mongodb.org/mongo-driver/v2/bson"
  	"go.mongodb.org/mongo-driver/v2/mongo"
  	"go.mongodb.org/mongo-driver/v2/mongo/options"
  )

  const (
  	indexName = "auto_embedding_vector_index"
  )

  // autoEmbedField represents the auto-embedding index field definition.
  type autoEmbedField struct {
  	Type     string `bson:"type"`     // "autoEmbed"
  	Modality string `bson:"modality"` // "text"
  	Path     string `bson:"path"`     // e.g. "summary"
  	Model    string `bson:"model"`    // e.g. "voyage-4"
  }

  // filterField represents a filter field in the vectorSearch index definition.
  type filterField struct {
  	Type string `bson:"type"` // "filter"
  	Path string `bson:"path"`
  }

  // autoEmbedIndexDefinition is the top-level index definition.
  type autoEmbedIndexDefinition struct {
  	Fields []any `bson:"fields"`
  }

  func main() {
  	// Replace with your MongoDB connection string.
  	uri := "<connection-string>"

  	// Create a context with a timeout for index creation and polling.
  	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Minute)
  	defer cancel()

  	// Connect to your deployment.
  	client, err := mongo.Connect(options.Client().ApplyURI(uri))
  	if err != nil {
  		log.Fatalf("Failed to connect to MongoDB: %v", err)
  	}
  	defer func() {
  		if err := client.Disconnect(context.Background()); err != nil {
  			log.Printf("Error disconnecting client: %v", err)
  		}
  	}()

  	// Access your database and collection.
  	db := client.Database("sample_airbnb")
  	coll := db.Collection("listingsAndReviews")

  	// 1. Create the auto-embedding vectorSearch index.
  	if err := createAutoEmbeddingIndex(ctx, coll); err != nil {
  		log.Fatalf("Failed to create auto-embedding index: %v", err)
  	}
  	fmt.Println("New search index named", indexName, "is building.")

  	// 2. Wait until the index is queryable (initial sync complete).
  	fmt.Println("Polling to check if the index is ready. This may take up to a minute.")
  	if err := waitForIndexQueryable(ctx, coll, indexName); err != nil {
  		log.Fatalf("Error while waiting for index to become queryable: %v", err)
  	}
  	fmt.Println(indexName, "is ready for querying.")
  }

  func createAutoEmbeddingIndex(ctx context.Context, coll *mongo.Collection) error {
  	// Define the index fields.
  	definition := autoEmbedIndexDefinition{
  		Fields: []any{
  			autoEmbedField{
  				Type:     "autoEmbed",
  				Modality: "text",
  				Path:     "summary",
  				Model:    "voyage-4",
  			},
  			filterField{
  				Type: "filter",
  				Path: "address.country",
  			},
  			filterField{
  				Type: "filter",
  				Path: "bedrooms",
  			},
  		},
  	}

  	// Set index name and type "vectorSearch".
  	opts := options.SearchIndexes().
  		SetName(indexName).
  		SetType("vectorSearch")

  	model := mongo.SearchIndexModel{
  		Definition: definition,
  		Options:    opts,
  	}

  	_, err := coll.SearchIndexes().CreateOne(ctx, model)
  	return err
  }

  func waitForIndexQueryable(ctx context.Context, coll *mongo.Collection, name string) error {
  	for {
  		// List just this index by name.
  		opts := options.SearchIndexes().SetName(name)
  		cursor, err := coll.SearchIndexes().List(ctx, opts)
  		if err != nil {
  			return fmt.Errorf("list search indexes: %w", err)
  		}

  		var results []bson.M
  		if err := cursor.All(ctx, &results); err != nil {
  			return fmt.Errorf("decode search index list: %w", err)
  		}

  		if len(results) > 0 {
  			if q, ok := results[0]["queryable"].(bool); ok && q {
  				return nil
  			}
  		}

  		select {
  		case <-ctx.Done():
  			return ctx.Err()
  		case <-time.After(5 * time.Second):
  			// Continue polling.
  		}
  	}
  }

  ```

- Replace the `<connection-string>` placeholder in the index definition
  with your deployment's connection string and save the file.

  To learn more, see [Driver](connect-via-driver).

To create the index, run the following command:

```shell
go run create-index.go
```

To define a MongoDB Vector Search index:

- Create a `.java` file.

  ```java
  touch vectorIndex.java
  ```

- Copy and paste the following index definition in to the file.

  ```java
  import com.mongodb.client.MongoClient;
  import com.mongodb.client.MongoClients;
  import com.mongodb.client.MongoCollection;
  import com.mongodb.client.MongoDatabase;
  import com.mongodb.client.model.SearchIndexModel;
  import com.mongodb.client.model.SearchIndexType;
  import org.bson.Document;

  import java.util.Arrays;
  import java.util.Collections;

  public class CreateIndex {
      public static void main(String[] args) throws InterruptedException {
          // connect to your deployment
          String uri = "<connectionString>";

          try (MongoClient client = MongoClients.create(uri)) {
              MongoDatabase database = client.getDatabase("sample_airbnb");
              MongoCollection<Document> collection = database.getCollection("listingsAndReviews");

              // define your MongoDB Vector Search index
              SearchIndexModel indexModel = new SearchIndexModel(
                  "vectorIndex",
                  new Document("fields",
                      Arrays.asList(
                          new Document("type", "autoEmbed")
                              .append("modality", "text")
                              .append("path", "summary")
                              .append("model", "voyage-4"),
                          new Document("type", "filter")
                              .append("path", "address.country"),
                          new Document("type", "filter")
                              .append("path", "bedrooms")
                      )
                  ),
                  SearchIndexType.vectorSearch()
              );

              // run the helper method
              String result = collection.createSearchIndexes(Collections.singletonList(indexModel)).get(0);
              System.out.println("New search index named " + result + " is building.");

              System.out.println("Polling to check if the index is ready. This may take up to a minute.");
              boolean isQueryable = false;
              while (!isQueryable) {
                  for (Document index : collection.listSearchIndexes()) {
                      if (result.equals(index.getString("name"))) {
                          String status = index.getString("status");
                          if ("READY".equals(status) || status == null) {
                              System.out.println(result + " is ready for querying.");
                              isQueryable = true;
                          }
                          break;
                      }
                  }

                  // wait for the index to be ready to query
                  if (!isQueryable) {
                      Thread.sleep(5000);
                  }
              }
          }
      }
  }
  ```

- Replace the `<connectionString>` in the index definition and
  save the file.

  To learn more, see [Driver](connect-via-driver).

To create the index, run the following commands:

```shell
javac vectorIndex.java
java vectorIndex
```

